```java
import org.springframework.cloud.gateway.route.RouteLocator;
import org.springframework.cloud.gateway.route.builder.RouteLocatorBuilder;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class GatewayConfiguration {

    @Bean
    public RouteLocator myRoutes(RouteLocatorBuilder builder) {
        return builder.routes()
                .route(p -> p
                        .path("/backend")
                        .filters(f -> f
                                .requestRateLimiter(config -> config
                                        .setRateLimiter(redisRateLimiterSpec -> redisRateLimiterSpec
                                                .setReplenishRate(500)
                                                .setBurstCapacity(1000)
                                                .setRequestedTokens(1))
                                )
                                .addRequestHeader("Hello", "World")
                        )
                        .uri("http://localhost:8081"))
                .build();
    }
}
```

In this example, we're defining a route with the path `/backend` and applying a `RequestRateLimiter` filter with the specified arguments. The `addRequestHeader` filter is also applied to add the `Hello: World` header to the request. The URI is set to `http://localhost:8081`.

